scwin.memJson = $c.data.getMemInfo($p);
scwin.sLoUpperLobranCd = $c.data.getMemInfo($p, "loUpperLobranCd"); //상위물류점소코드
scwin.sLoUpperLobranNm = $c.data.getMemInfo($p, "loUpperLobranNm"); //상위물류점소

scwin.sUserId = scwin.memJson.userId; //사용자
scwin.sUserClsCd = scwin.memJson.userClsCd; //사용자 구분코드
scwin.sClntNo = $c.gus.cfIsNull($p, scwin.memJson.clntNo) ? '' : scwin.memJson.clntNo; //거래처코드
scwin.sClntNm = scwin.memJson.clntNm; //거래처명

scwin.strCurDate = WebSquare.date.getCurrentServerDate(); // 서버를 기준으로 현재 날짜 반환
scwin.strFromDate = scwin.strCurDate.substring(0, 8);
scwin.strToDate = scwin.strCurDate.substring(0, 8);
scwin.strDate = scwin.strFromDate + scwin.strToDate;
if (scwin.sLoUpperLobranCd == null) scwin.sLoUpperLobranCd = "";
scwin.onpageload = function () {
  $c.data.setPopupTitle($p, "벌크하불요율일괄등록(Excel업로드)");
  scwin.onloadComplete();
  udc_excel.setDisabledBtn("btn_excelUp", true); // 엑셀업로드 disabled
  $c.gus.cfDisableObjects($p, [btn_update]);
};
scwin.onloadComplete = function () {
  /*배차점소(소속지사) setting*/
  sbm_lobran.action = "/ds.co.RetreiveLoBranCMD.do";
  $c.sbm.execute($p, sbm_lobran);
};
scwin.sbm_lobran_submitdone = function () {
  //소속지사 세팅
  lc_lobranCd.setValue(scwin.sLoUpperLobranCd);
  //화주코드
  ed_bilgMchtCd.focus();
};
scwin.btn_retrieve_onclick = function (e) {
  console.log("scwin.btn_retrieve_onclick");
  scwin.f_Retrieve();
};
scwin.f_Retrieve = function () {
  // debugger;

  if (ed_bilgMchtCd.getValue() == "") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["화주코드"]);
    ed_bilgMchtCd.focus();
    return;
  }
  if (ed_bilgMchtCdNm.getValue() == "") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["화주명"]);
    ed_bilgMchtCdNm.focus();
    return;
  }
  if (lc_ctrtNo.getValue() == "") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["계약번호"]);
    lc_ctrtNo.focus();
    return;
  }
  dma_retrieve.setEmptyValue();
  dma_retrieve.set("alloccarBranCd", lc_lobranCd.getValue()); //배차점소
  dma_retrieve.set("ctrtNo", lc_ctrtNo.getValue()); //계약번호
  dma_retrieve.set("adptDt", scwin.strDate.substring(0, 8));

  //tr_retrieve.Post();
  $c.sbm.execute($p, sbm_retrieve);
};

//조회callback
scwin.sbm_retrieve_submitdone = function (e) {
  let nCnt = ds_tariff.getRowCount();
  if (e.responseJSON.resultDataSet[0].Msg == "FAIL") {
    return;
  }
  if (nCnt == 0) {
    total.setValue(nCnt);
    $c.gus.cfAlertMsg($p, "조회할 데이타가 없습니다.");
  } else {
    //cfEnableObjects([btn_Upt, document.getElementById("DYNAMIC_FILE_1") ,document.getElementById("btnDrmRight")]);
    udc_excel.setDisabledBtn("btn_excelUp", false); // 엑셀업로드 enabled
    $c.gus.cfEnableObjects($p, [btn_update]);
    total.setValue(nCnt);
  }
};
scwin.udc_bilgMchtCd_onblurCodeEvent = function (e) {
  if (ed_bilgMchtCd.getValue() == "") return;
  scwin.f_openPopUp(1, ed_bilgMchtCd.getValue(), "", 'T', 'F');
};
scwin.udc_bilgMchtCd_onclickEvent = function (e) {
  scwin.f_openPopUp(1, ed_bilgMchtCd.getValue(), ed_bilgMchtCdNm.getValue(), 'F', 'F');
};
scwin.udc_bilgMchtCd_onviewchangeNameEvent = function (info) {
  scwin.f_chkOpenCommonPopUp(ed_bilgMchtCdNm, ed_bilgMchtCd, 1, false);
};

