scwin.udc_bilgMchtCd_callBackFunc = function (ret) {
  //debugger;
  // console.log(ret); 
  //cfSetReturnValue(rtnList, bilgMchtCd, bilgMcht);
  $c.gus.cfSetReturnValue($p, ret, ed_bilgMchtCd, ed_bilgMchtCdNm);
  if (!$c.gus.cfIsNull($p, ret) && ret[0] != "N/A") {
    // if (ds_retrieve2.CountRow == 0) {
    // 		var GAUCE_DATASET_HEADER = "ctrtClntNo:STRING(11), ctrtCheck:STRING(2), ctrtDtYn:DECIMAL(1)"; 
    // 		ds_retrieve2.SetDataHeader(GAUCE_DATASET_HEADER);
    // }
    dma_retrieve2.setEmptyValue();
    dma_retrieve2.set("ctrtClntNo", ret[0]); //화주코드  bilgMchtCd
    dma_retrieve2.set("ctrtCheck", "0"); //계약완료가 아닌 모든 계약번호 가져오기 위한 임시 값
    dma_retrieve2.set("ctrtDtYn", 1);

    //tr_retrieve2.Post();
    $c.sbm.execute($p, sbm_retrieve2);
  }
  //ctrtNo.Enable = true;
  lc_ctrtNo.setDisabled(false);
};

