scwin.f_downExcelSheet = async function (e) {
  let fileName = '벌크하불요율' + '_' + scwin.strDate.substring(0, 8);
  if (ds_tariff.getRowCount() != 0) {
    let cfrm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      // let arg = await $c.win.confirm(" [Yes] SAVE To CSV \n [No] Grid To Excel");
      var ext = udc_excel.getUpExt();
      if (ext == "1") {
        // xlsx, csv(1) 선택값
        //options.type				[default: 1, 0] Grid 저장 형태 (0이면 데이터 형태,1이면 표시 방식)
        $c.data.downloadGridViewCSV($p, gr_tariff, {
          fileName: fileName + ".csv",
          sheetName: fileName,
          type: "0",
          hidden: "1",
          //Grid의 숨겨진 Column에 대한 저장 여부(0이면 저장 하지 않음,1이면 저장)
          hiddenVisible: true,
          delim: ",",
          //[default: ';'] CSV 파일에서 데이터를 구분할 구분자
          removeQuotation: "1" //default: 0, 1] 값에 ", ' 가 들어있는 경우 ", '를 지울지 여부 (0 : 안 지움, 1 : 지움)
        });
      } else {
        //type: options.type || "1", //String, [defalut: 0] type이 0인 경우 실제 데이터 1인 경우 눈에 보이는 데이터를  2이면 들어가 있는 data 그대로(filter무시 expression 타입의 셀은 나오지 않음)
        $c.data.downloadGridViewExcel($p, gr_tariff, {
          fileName: fileName + ".xlsx",
          sheetName: fileName,
          hidden: "1",
          hiddenVisible: true,
          removeQuotation: "0"
        });
      }
    }
  } else {
    $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002);
  }
};

