/**
 * 엑셀 파일 업로드
 * TOBE UDC 사용으로 로직만 복사해서 사용(gr_grid_onfilereadend 이벤트)
 */
scwin.f_Import = async function () {
  ///////////위 f_Upload 부분
  // 1. 그리드 렌더링 잠시 중단 (성능 향상)
  // gr_tariff.ReDraw = "false";
  // gr_tariff.advancedRender("enter"); 

  ds_excel.removeAll();
  ds_temp.removeAll();
  for (let i = 0; i < ds_tariff.getRowCount(); i++) {
    // ds_excel.DataId = fileUploadGDS.NameValue( 0, "filePath" );//엑셀업로드
    ds_excel.setJSON([ds_tariff.getRowJSON(i)], true);
  }
  $c.gus.cfProgressWinOpen($p);
  ////////////////

  if (ds_excel.getRowCount() == 0) {
    await $c.gus.cfProgressWinClose($p);
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_003);
    return;
  }

  // 로드된 엑셀 데이터 기본검증 / 로드된 엑셀 데이터의 열값이 다르면 프로그램 종료 
  // 첫번째 행에 헤더값이 아닌 다른 값이 있으면, 경고 메세지 출력후 종료 
  let cnt = 24;
  if (ds_excel.getColumnCount() < cnt) {
    await $c.gus.cfProgressWinClose($p);
    await $c.gus.cfAlertMsg($p, "업로드 cvs 파일의 형식이 잘못되었습니다." + "\n파일형식을 확인후 다시 업로드하시길 바랍니다." + "\n컬럼값이 상이합니다. [형식=" + cnt + "개] 입력한값 => " + ds_excel.getColumnCount());
    return;
  }
  let i = 0;
  // let temp = new String();

  // 2. 대량 데이터 수정 작업
  // for (i=1;i<=ds_excel.getRowCount(); i++) {	
  for (i = 0; i < ds_excel.getRowCount(); i++) {
    // 요율(Q열 18), 변경요율(R 19)
    //ds_excel.NameValue(i, ds_excel.ColumnID(18) ) = f_DataFomatChg(ds_excel.NameValue(i, ds_excel.ColumnID(18) ));	// 항목에 ',', ' ' 값이 있을경우 제거
    //ds_excel.NameValue(i, ds_excel.ColumnID(19) ) = f_DataFomatChg(ds_excel.NameValue(i, ds_excel.ColumnID(19) ));
    ds_excel.setCellData(i, ds_excel.getColumnID(17), scwin.f_DataFomatChg(ds_excel.getCellData(i, ds_excel.getColumnID(17)))); // 항목에 ',', ' ' 값이 있을경우 제거 
    ds_excel.setCellData(i, ds_excel.getColumnID(18), scwin.f_DataFomatChg(ds_excel.getCellData(i, ds_excel.getColumnID(18))));

    // 변경요율(R 19) 에 null이나 공백이 있을경우 경고메세지 출력후 종료 
    if (ds_excel.getCellData(i, ds_excel.getColumnID(18)) == "" || ds_excel.getCellData(i, ds_excel.getColumnID(18)) == null) {
      await $c.gus.cfProgressWinClose($p);
      await $c.gus.cfAlertMsg($p, "업로드 cvs 파일의 데이터가 잘못되었습니다." + "\n[" + i + "] 번째 행의 [변경요율] 값이 없습니다.\n사용하신 CVS파일의 데이터를 확인 후,\n다시 업로드하시길 바랍니다.");
      return;
    }
  }
  if (await scwin.f_AddRowUploaded()) {
    $c.gus.cfProgressWinClose($p);
    await $c.gus.cfAlertMsg($p, "업로드작업이 완료되었습니다.");
  }

  // 3. 다시 렌더링 시작 및 화면 갱신
  //gr_tariff.ReDraw = "true";
  // gr_tariff.refresh();
  //gr_tariff.advancedRender("exit"); 

  //tr_excelUpload.Post();
  $c.sbm.execute($p, sbm_excelUpload);
};
