scwin.f_excelUpload = async function () {
  // 설정:data.xml 파일 참고

  var ext = udc_excel.getUpExt();
  var options;
  if (ext == "1") {
    // xlsx, csv(1) 선택값
    var options = {
      "header": 1,
      //헤더의 존재 여부 (0 : 헤더 행의 수 무시하고 전부 업로드, 1 : 헤더 행의 수 만큼 건너 뜀)
      "type": "1",
      //[default: 1, 0]데이터 형태 (0이면 실 데이터 형태,1이면 display 표시 방식)
      //"startRowIndex": 0,
      "hidden": 1,
      "fillHidden": 1,
      //hidden Column에 빈 값을 넣을지를 결정하기 위한 int형 숫자(1이면 hidden Column에 빈 값을 저장하지 않음,0이면 hidden column이 저장되어있지 않은 csv File이라 간주하고 hidden Column에 빈 값을 넣어줌)(hidden이 0인 경우에는 fillhidden은 영향을 끼치지 않음)
      //"delim": ",",     //[default: ',']CSV 파일에서 데이터를 구분할 구분자
      "status": "C"
    };
    await $c.data.uploadGridViewCSV($p, gr_tariff, options); // CSV를 선택하였을 경우
  } else {
    var options = {
      "headerExist": 1,
      //그리드의 데이터에 header가 있는지 여부(1이면 header 존재 0이면 없음)
      "type": "1",
      //[default: 0] 1이면 엑셀 파일이 그리드의 보이는 결과로 만들어져있을때 0이면 엑셀 파일이 그리드의 실제 데이터로 구성되어있을때
      "startRowIndex": 0,
      //excel파일에서 그리드의 데이터가 시작되는 행의 번호(헤더 포함)
      "hidden": 1,
      "status": "C"
    };
    await $c.data.uploadGridViewExcel($p, gr_tariff, options); // XLSX를 선택하였을 경우
  }
};

